/**
 * Lender LLPA data loader.
 *
 * Returns lender-specific LLPA adjustments extracted from rate sheet XLSX files.
 * Data is generated by: node scripts/extract-lender-llpas.js
 *
 * Usage:
 *   import { getLenderLLPAs } from '@/data/lender-llpas';
 *   const llpas = getLenderLLPAs('everstream');
 */

import everstreamData from './everstream.json';
import amwestData from './amwest.json';
import swmcData from './swmc.json';

const LENDER_DATA = {
  everstream: everstreamData,
  amwest: amwestData,
  swmc: swmcData,
};

/**
 * Load and return LLPA data for a given lender.
 * @param {string} lenderId - One of: 'everstream', 'amwest', 'swmc'
 * @returns {Object|null} Parsed LLPA data, or null if lender not found
 */
export function getLenderLLPAs(lenderId) {
  if (!lenderId) return null;
  return LENDER_DATA[lenderId.toLowerCase()] || null;
}

/**
 * List all available lender IDs that have LLPA data.
 * @returns {string[]}
 */
export function getAvailableLenders() {
  return Object.keys(LENDER_DATA);
}
